window.__SCHOLARSHIP_DETAIL_CB && window.__SCHOLARSHIP_DETAIL_CB({"id":"27325","status":"ok","fetched_at":"2026-06-10T23:35:13Z","official_link":null,"org_about":"Mohamed bin Zayed University of Artificial Intelligence (MBZUAI) is a graduate-level, research-based academic institution that is located in Abu Dhabi. The university was established in 2019 and offers programs in the Artificial Intelligence field for both local and international students. The establishment of MBZUAI is part of the United Arab Emirates strategy for Artificial Intelligence 2031, for which came the appointment of the world\u0027s first Minister of State for Artificial Intelligence.","en":{"lang":"en","title":"Mohammed bin Zayed University Artificial Intelligence Scholarship Fully Funded | Register for free!","sections":[{"header":"Opportunity description","body":"\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cp\u003eIf you\u0026#39;re aiming to achieve your academic ambitions in the field of Artificial Intelligence, the Mohammed bin Zayed University of Artificial Intelligence (MBZUAI) Scholarship offers an exceptional opportunity for students from around the world. The scholarship provides full funding for a Master\u0026#39;s or PhD degree in an innovative and advanced educational environment in the heart of Abu Dhabi, United Arab Emirates.\u003c/p\u003e\u003ch3\u003eWhy Choose the Mohammed bin Zayed University of Artificial Intelligence Scholarship?\u003c/h3\u003e\u003cul\u003e\u003cli\u003e\u003cstrong\u003ePrime Location:\u003c/strong\u003e Abu Dhabi, the UAE capital, is one of the leading global innovation hubs.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003ePioneering University:\u003c/strong\u003e Established in 2026, MBZUAI is the first graduate university specializing in AI studies.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003eGlobal Curriculum:\u003c/strong\u003e The program focuses on key areas such as computer vision, machine learning, and natural language processing.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003eInclusive Environment:\u003c/strong\u003e The university integrates advanced education, scientific research, and practical application.\u003c/li\u003e\u003c/ul\u003e\u003ch3\u003eBenefits of the Mohammed bin Zayed University of Artificial Intelligence Scholarship\u003c/h3\u003e\u003cul\u003e\u003cli\u003e\u003cstrong\u003eFull Tuition Coverage:\u003c/strong\u003e Students can focus on their studies without the burden of tuition fees.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003eGenerous Monthly Stipend:\u003c/strong\u003e\u003cul\u003e\u003cli\u003e10,000 AED for non-UAE nationals.\u003c/li\u003e\u003cli\u003e36,000 AED for UAE nationals.\u003c/li\u003e\u003c/ul\u003e\u003c/li\u003e\u003cli\u003e\u003cstrong\u003eComprehensive Health Insurance:\u003c/strong\u003e Coverage for international students.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003eFree On-Campus Housing:\u003c/strong\u003e Fully equipped with all amenities.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003eAnnual Travel Tickets:\u003c/strong\u003e For international students.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003eAdditional Perks:\u003c/strong\u003e\u003cul\u003e\u003cli\u003eCoverage of books and study materials.\u003c/li\u003e\u003cli\u003eSupport for attending scientific conferences.\u003c/li\u003e\u003cli\u003eAssistance with residence visa applications.\u003c/li\u003e\u003c/ul\u003e\u003c/li\u003e\u003c/ul\u003e\u003ch3\u003eAvailable Programs under the MBZUAI Scholarship:\u003c/h3\u003e\u003col\u003e\u003cli\u003e\u003cstrong\u003eMaster\u0026rsquo;s Program:\u003c/strong\u003e\u003cul\u003e\u003cli\u003eDuration: 2 years.\u003c/li\u003e\u003cli\u003eObjective: To provide students with a strong foundation in AI.\u003c/li\u003e\u003c/ul\u003e\u003c/li\u003e\u003cli\u003e\u003cstrong\u003ePhD Program:\u003c/strong\u003e\u003cul\u003e\u003cli\u003eDuration: 4 years.\u003c/li\u003e\u003cli\u003eObjective: To develop research and innovation skills to address future challenges.\u003c/li\u003e\u003c/ul\u003e\u003c/li\u003e\u003c/ol\u003e\u003ch3\u003eAdmission Requirements for the Mohammed bin Zayed University of Artificial Intelligence Scholarship:\u003c/h3\u003e\u003cul\u003e\u003cli\u003e\u003cstrong\u003eMaster\u0026rsquo;s Program:\u003c/strong\u003e\u003cul\u003e\u003cli\u003eA Bachelor\u0026#39;s degree with a minimum GPA of Very Good.\u003c/li\u003e\u003c/ul\u003e\u003c/li\u003e\u003cli\u003e\u003cstrong\u003ePhD Program:\u003c/strong\u003e\u003cul\u003e\u003cli\u003eA Master\u0026#39;s degree with an Excellent grade.\u003c/li\u003e\u003c/ul\u003e\u003c/li\u003e\u003cli\u003e\u003cstrong\u003eAdditional Requirements:\u003c/strong\u003e\u003cul\u003e\u003cli\u003eEnglish proficiency certificate (TOEFL or IELTS).\u003c/li\u003e\u003cli\u003eGRE results (optional but preferred).\u003c/li\u003e\u003cli\u003eStrong background in mathematics and programming.\u003c/li\u003e\u003cli\u003eResearch or professional experience in AI.\u003c/li\u003e\u003c/ul\u003e\u003c/li\u003e\u003c/ul\u003e\u003ch3\u003eApplication Deadlines:\u003c/h3\u003e\u003cp\u003eApplications typically open at the end of the year and close by February 27. It\u0026#39;s recommended to always check the official university website for precise deadlines.\u003c/p\u003e\u003ch3\u003eRequired Documents for Application:\u003c/h3\u003e\u003cul\u003e\u003cli\u003ePassport copy.\u003c/li\u003e\u003cli\u003eAcademic transcripts and certificates.\u003c/li\u003e\u003cli\u003eProof of English proficiency.\u003c/li\u003e\u003cli\u003eUpdated CV.\u003c/li\u003e\u003cli\u003eA motivational letter outlining your reasons for applying.\u003c/li\u003e\u003cli\u003eThree recommendation letters from academic or professional references.\u003c/li\u003e\u003cli\u003eResearch proposal (for PhD applicants).\u003c/li\u003e\u003c/ul\u003e\u003ch3\u003eHow to Apply for the MBZUAI Scholarship:\u003c/h3\u003e\u003cul\u003e\u003cli\u003eVisit the official MBZUAI website.\u003c/li\u003e\u003cli\u003eCreate an account on the application portal.\u003c/li\u003e\u003cli\u003eComplete the application form accurately.\u003c/li\u003e\u003cli\u003eUpload required documents and ensure their quality.\u003c/li\u003e\u003cli\u003eSubmit the application before the deadline.\u003c/li\u003e\u003c/ul\u003e\u003ch3\u003eResearch and Internship Opportunities at MBZUAI:\u003c/h3\u003e\u003cul\u003e\u003cli\u003e\u003cstrong\u003eGlobal Partnerships:\u003c/strong\u003e The university collaborates with major companies like Google and Microsoft, offering students opportunities for training and research.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003eReal-World Projects:\u003c/strong\u003e Students engage in practical applications and research, gaining hands-on experience.\u003c/li\u003e\u003c/ul\u003e\u003ch3\u003eTips for Successful Application:\u003c/h3\u003e\u003cul\u003e\u003cli\u003eFocus your statement of purpose on your future goals and passion for AI.\u003c/li\u003e\u003cli\u003ePrepare thoroughly for the interview process.\u003c/li\u003e\u003cli\u003eEnsure all submitted documents are accurate and of high quality.\u003c/li\u003e\u003c/ul\u003e\u003ch3\u003eAbout Mohammed bin Zayed University of Artificial Intelligence:\u003c/h3\u003e\u003cp\u003eEstablished in 2026, MBZUAI is a graduate-level university specializing in AI research. The university aims to solidify the UAE\u0026#39;s position as a global hub for AI innovation. It features:\u003c/p\u003e\u003cul\u003e\u003cli\u003eA state-of-the-art educational environment.\u003c/li\u003e\u003cli\u003eA faculty of top-tier international AI scholars and researchers.\u003c/li\u003e\u003cli\u003eA focus on three primary fields: computer vision, machine learning, and natural language processing.\u003c/li\u003e\u003c/ul\u003e\u003ch2\u003e\u003cstrong\u003eFAQs about the Mohamed bin Zayed University AI Scholarship:\u003c/strong\u003e\u003c/h2\u003e\u003cp\u003e\u003cstrong\u003eWhat is the Mohamed bin Zayed University AI Scholarship?\u003c/strong\u003e\u003cbr\u003eIt is a fully funded scholarship for studying a master\u0026#39;s or doctoral degree in Artificial Intelligence at Mohamed bin Zayed University in Abu Dhabi. This scholarship provides students with the opportunity to study in an innovative and advanced educational environment.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eWhat are the benefits of the scholarship?\u003c/strong\u003e\u003cbr\u003eThe scholarship covers tuition fees, provides an attractive monthly stipend, free on-campus accommodation, comprehensive health insurance, and covers book and study material costs. International students also receive annual travel tickets.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eWhat are the eligibility requirements for applying?\u003c/strong\u003e\u003cbr\u003eApplicants for the master\u0026#39;s program must have a bachelor\u0026#39;s degree with a minimum GPA of \u0026quot;Very Good\u0026quot;, and for the PhD program, applicants must have a master\u0026#39;s degree with \u0026quot;Excellent\u0026quot; grades. Additionally, applicants need to submit proof of English proficiency (TOEFL or IELTS), and GRE scores are preferred.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eWhat documents are required for applying?\u003c/strong\u003e\u003cbr\u003eRequired documents include a copy of the passport, academic certificates, English proficiency certificate, CV, a motivational letter, recommendation letters, and a research proposal (for PhD applicants).\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eHow can I apply for the scholarship?\u003c/strong\u003e\u003cbr\u003eYou need to visit the university\u0026#39;s official website and create an account on the application portal. Afterward, fill out the application form and upload the required documents before the deadline.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eWhat are the application deadlines?\u003c/strong\u003e\u003cbr\u003eApplications typically open at the end of the year and close by February 27 of the following year. It is recommended to check the official university website for the exact dates.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eAre there internship or research opportunities?\u003c/strong\u003e\u003cbr\u003eThe university offers internship opportunities in collaboration with global companies like Google and Microsoft. Students also engage in applied research that enhances their practical experience.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eWhat happens after acceptance?\u003c/strong\u003e\u003cbr\u003eAccepted students will receive a detailed study plan and will be assigned an academic advisor to help define their academic goals. They will be able to participate in scientific conferences and internships with international companies.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eAre there opportunities for Emirati students?\u003c/strong\u003e\u003cbr\u003eYes, Emirati students receive a monthly stipend of 36,000 AED in addition to other benefits.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eIs the scholarship available for international students?\u003c/strong\u003e\u003cbr\u003eYes, the scholarship is available for international students, providing a monthly stipend of 10,000 AED along with other benefits such as free accommodation and health insurance\u003c/p\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e"},{"header":"Benefits","body":"\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cbr\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e"},{"header":"Eligibility criteria","body":"\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cbr\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e"}]},"ar":{"lang":"ar","title":"\u0645\u0646\u062d\u0629 \u062c\u0627\u0645\u0639\u0629 \u0645\u062d\u0645\u062f \u0628\u0646 \u0632\u0627\u064a\u062f \u0644\u0644\u0630\u0643\u0627\u0621 \u0627\u0644\u0627\u0635\u0637\u0646\u0627\u0639\u064a \u0645\u0645\u0648\u0644\u0629 \u0628\u0627\u0644\u0643\u0627\u0645\u0644 | \u0633\u062c\u0644 \u0645\u062c\u0627\u0646\u0627\u064b!","sections":[{"header":"\u0648\u0635\u0641","body":"\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cp\u003e\u0625\u0630\u0627 \u0643\u0646\u062a \u062a\u0633\u0639\u0649 \u0644\u062a\u062d\u0642\u064a\u0642 \u0637\u0645\u0648\u062d\u0627\u062a\u0643 \u0627\u0644\u0623\u0643\u0627\u062f\u064a\u0645\u064a\u0629 \u0641\u064a \u0645\u062c\u0627\u0644 \u0627\u0644\u0630\u0643\u0627\u0621 \u0627\u0644\u0627\u0635\u0637\u0646\u0627\u0639\u064a\u060c \u0641\u0625\u0646 \u003cstrong\u003e\u0645\u0646\u062d\u0629 \u062c\u0627\u0645\u0639\u0629 \u0645\u062d\u0645\u062f \u0628\u0646 \u0632\u0627\u064a\u062f \u0644\u0644\u0630\u0643\u0627\u0621 \u0627\u0644\u0627\u0635\u0637\u0646\u0627\u0639\u064a\u003c/strong\u003e \u062a\u0642\u062f\u0645 \u0627\u0633\u062a\u062b\u0646\u0627\u0626\u064a\u0629 \u0644\u0644\u0637\u0644\u0627\u0628 \u0645\u0646 \u062c\u0645\u064a\u0639 \u0623\u0646\u062d\u0627\u0621 \u0627\u0644\u0639\u0627\u0644\u0645. \u062a\u0648\u0641\u0631 \u0627\u0644\u0645\u0646\u062d\u0629 \u062a\u0645\u0648\u064a\u0644\u0627\u064b \u0643\u0627\u0645\u0644\u0627\u064b \u0644\u062f\u0631\u0627\u0633\u0629 \u0627\u0644\u0645\u0627\u062c\u0633\u062a\u064a\u0631 \u0623\u0648 \u0627\u0644\u062f\u0643\u062a\u0648\u0631\u0627\u0647 \u0641\u064a \u0628\u064a\u0626\u0629 \u062a\u0639\u0644\u064a\u0645\u064a\u0629 \u0645\u0628\u062a\u0643\u0631\u0629 \u0648\u0645\u062a\u0642\u062f\u0645\u0629 \u0641\u064a \u0642\u0644\u0628 \u0645\u062f\u064a\u0646\u0629 \u003cstrong\u003e\u0623\u0628\u0648 \u0638\u0628\u064a\u003c/strong\u003e\u060c \u0627\u0644\u0625\u0645\u0627\u0631\u0627\u062a \u0627\u0644\u0639\u0631\u0628\u064a\u0629 \u0627\u0644\u0645\u062a\u062d\u062f\u0629.\u003c/p\u003e\u003cp\u003e\u062a\u0635\u0641\u062d \u0627\u0644\u0622\u0646: \u0645\u0646\u062d \u062f\u0631\u0627\u0633\u064a\u0629 \u0641\u064a \u0627\u0644\u0625\u0645\u0627\u0631\u0627\u062a\u003c/p\u003e\u003ch2\u003e\u003cstrong\u003e\u0644\u0645\u0627\u0630\u0627 \u0645\u0646\u062d\u0629 \u062c\u0627\u0645\u0639\u0629 \u0645\u062d\u0645\u062f \u0628\u0646 \u0632\u0627\u064a\u062f \u0644\u0644\u0630\u0643\u0627\u0621 \u0627\u0644\u0627\u0635\u0637\u0646\u0627\u0639\u064a\u061f\u003c/strong\u003e\u003c/h2\u003e\u003cul\u003e\u003cli\u003e\u003cstrong\u003e\u0645\u0648\u0642\u0639 \u0645\u062a\u0645\u064a\u0632\u003c/strong\u003e: \u0623\u0628\u0648 \u0638\u0628\u064a\u060c \u0627\u0644\u0639\u0627\u0635\u0645\u0629 \u0627\u0644\u0625\u0645\u0627\u0631\u0627\u062a\u064a\u0629 \u0648\u0648\u0627\u062d\u062f\u0629 \u0645\u0646 \u0623\u0628\u0631\u0632 \u0645\u0631\u0627\u0643\u0632 \u0627\u0644\u0627\u0628\u062a\u0643\u0627\u0631 \u0639\u0627\u0644\u0645\u064a\u064b\u0627.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u062c\u0627\u0645\u0639\u0629 \u0631\u0627\u0626\u062f\u0629\u003c/strong\u003e: \u062a\u0623\u0633\u0633\u062a \u062c\u0627\u0645\u0639\u0629 \u0645\u062d\u0645\u062f \u0628\u0646 \u0632\u0627\u064a\u062f \u0639\u0627\u0645 2026 \u0643\u0623\u0648\u0644 \u062c\u0627\u0645\u0639\u0629 \u0644\u0644\u062f\u0631\u0627\u0633\u0627\u062a \u0627\u0644\u0639\u0644\u064a\u0627 \u0627\u0644\u0645\u062a\u062e\u0635\u0635\u0629 \u0641\u064a \u0627\u0644\u0630\u0643\u0627\u0621 \u0627\u0644\u0627\u0635\u0637\u0646\u0627\u0639\u064a.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0645\u0646\u0647\u062c \u0639\u0627\u0644\u0645\u064a\u003c/strong\u003e: \u064a\u0631\u0643\u0632 \u0639\u0644\u0649 \u0627\u0644\u0631\u0624\u064a\u0629 \u0627\u0644\u062d\u0627\u0633\u0648\u0628\u064a\u0629\u060c \u062a\u0639\u0644\u0645 \u0627\u0644\u0622\u0644\u0629\u060c \u0648\u0645\u0639\u0627\u0644\u062c\u0629 \u0627\u0644\u0644\u063a\u0627\u062a \u0627\u0644\u0637\u0628\u064a\u0639\u064a\u0629.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0628\u064a\u0626\u0629 \u0634\u0627\u0645\u0644\u0629\u003c/strong\u003e: \u062a\u062c\u0645\u0639 \u0628\u064a\u0646 \u0627\u0644\u062a\u0639\u0644\u064a\u0645 \u0627\u0644\u0645\u062a\u0642\u062f\u0645\u060c \u0627\u0644\u0628\u062d\u062b \u0627\u0644\u0639\u0644\u0645\u064a\u060c \u0648\u0627\u0644\u062a\u0637\u0628\u064a\u0642 \u0627\u0644\u0639\u0645\u0644\u064a.\u003c/li\u003e\u003c/ul\u003e\u003cp\u003e\u062a\u0642\u062f\u0645 \u0627\u0644\u0622\u0646: \u0645\u0646\u062d\u0629 \u0627\u0644\u062c\u0627\u0645\u0639\u0629 \u0627\u0644\u0642\u0627\u0633\u0645\u064a\u0629 \u0645\u0645\u0648\u0644\u0629 \u0628\u0627\u0644\u0643\u0627\u0645\u0644\u003c/p\u003e\u003ch2\u003e\u003cstrong\u003e\u0645\u0632\u0627\u064a\u0627 \u0645\u0646\u062d\u0629 \u062c\u0627\u0645\u0639\u0629 \u0645\u062d\u0645\u062f \u0628\u0646 \u0632\u0627\u064a\u062f \u0644\u0644\u0630\u0643\u0627\u0621 \u0627\u0644\u0627\u0635\u0637\u0646\u0627\u0639\u064a\u003c/strong\u003e\u003c/h2\u003e\u003col\u003e\u003cli\u003e\u003cstrong\u003e\u0631\u0633\u0648\u0645 \u062f\u0631\u0627\u0633\u064a\u0629 \u0645\u062c\u0627\u0646\u064a\u0629 \u0628\u0627\u0644\u0643\u0627\u0645\u0644\u003c/strong\u003e: \u062a\u062a\u064a\u062d \u0644\u0644\u0637\u0644\u0627\u0628 \u0627\u0644\u062a\u0631\u0643\u064a\u0632 \u0639\u0644\u0649 \u062a\u0639\u0644\u064a\u0645\u0647\u0645 \u062f\u0648\u0646 \u0623\u0639\u0628\u0627\u0621 \u0645\u0627\u0644\u064a\u0629.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0631\u0627\u062a\u0628 \u0634\u0647\u0631\u064a \u0645\u063a\u0631\u064a\u003c/strong\u003e:\u003cul\u003e\u003cli\u003e10,000 \u062f\u0631\u0647\u0645 \u0644\u063a\u064a\u0631 \u0627\u0644\u0625\u0645\u0627\u0631\u0627\u062a\u064a\u064a\u0646.\u003c/li\u003e\u003cli\u003e36,000 \u062f\u0631\u0647\u0645 \u0644\u0644\u0625\u0645\u0627\u0631\u0627\u062a\u064a\u064a\u0646.\u003c/li\u003e\u003c/ul\u003e\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u062a\u0623\u0645\u064a\u0646 \u0635\u062d\u064a \u0634\u0627\u0645\u0644\u003c/strong\u003e: \u064a\u063a\u0637\u064a \u0627\u0644\u0637\u0644\u0627\u0628 \u0627\u0644\u062f\u0648\u0644\u064a\u064a\u0646.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0633\u0643\u0646 \u0645\u062c\u0627\u0646\u064a \u062f\u0627\u062e\u0644 \u0627\u0644\u062d\u0631\u0645 \u0627\u0644\u062c\u0627\u0645\u0639\u064a\u003c/strong\u003e: \u0645\u062c\u0647\u0632 \u0628\u0643\u0627\u0641\u0629 \u0627\u0644\u062e\u062f\u0645\u0627\u062a.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u062a\u0630\u0627\u0643\u0631 \u0633\u0641\u0631 \u0633\u0646\u0648\u064a\u0629\u003c/strong\u003e: \u0644\u0644\u0637\u0644\u0627\u0628 \u0627\u0644\u062f\u0648\u0644\u064a\u064a\u0646.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0645\u0632\u0627\u064a\u0627 \u0625\u0636\u0627\u0641\u064a\u0629\u003c/strong\u003e:\u003cul\u003e\u003cli\u003e\u062a\u063a\u0637\u064a\u0629 \u062a\u0643\u0627\u0644\u064a\u0641 \u0627\u0644\u0643\u062a\u0628 \u0648\u0627\u0644\u0645\u0648\u0627\u062f \u0627\u0644\u062f\u0631\u0627\u0633\u064a\u0629.\u003c/li\u003e\u003cli\u003e\u062f\u0639\u0645 \u0644\u0644\u0645\u0634\u0627\u0631\u0643\u0629 \u0641\u064a \u0627\u0644\u0645\u0624\u062a\u0645\u0631\u0627\u062a \u0627\u0644\u0639\u0644\u0645\u064a\u0629.\u003c/li\u003e\u003cli\u003e\u0645\u0633\u0627\u0639\u062f\u0629 \u0641\u064a \u062a\u0623\u0634\u064a\u0631\u0629 \u0627\u0644\u0625\u0642\u0627\u0645\u0629.\u003c/li\u003e\u003c/ul\u003e\u003c/li\u003e\u003c/ol\u003e\u003cp\u003e\u0625\u0644\u064a\u0643 \u0627\u0644\u0645\u0632\u064a\u062f: \u0645\u0646\u062d\u0629 \u062c\u0627\u0645\u0639\u0629 \u0627\u0644\u0645\u0644\u0643 \u0633\u0639\u0648\u062f \u0645\u0645\u0648\u0644\u0629 \u0628\u0627\u0644\u0643\u0627\u0645\u0644 \u0641\u064a \u0627\u0644\u0633\u0639\u0648\u062f\u064a\u0629\u003c/p\u003e\u003ch2\u003e\u003cstrong\u003e\u0627\u0644\u0628\u0631\u0627\u0645\u062c \u0627\u0644\u062f\u0631\u0627\u0633\u064a\u0629 \u0627\u0644\u0645\u062a\u0627\u062d\u0629 \u0644\u0645\u0646\u062d\u0629 \u0645\u062d\u0645\u062f \u0628\u0646 \u0632\u0627\u064a\u062f \u0644\u0644\u0630\u0643\u0627\u0621 \u0627\u0644\u0627\u0635\u0637\u0646\u0627\u0639\u064a:\u003c/strong\u003e\u003c/h2\u003e\u003ch3\u003e\u003cstrong\u003e1. \u0627\u0644\u0645\u0627\u062c\u0633\u062a\u064a\u0631\u003c/strong\u003e:\u003c/h3\u003e\u003cul\u003e\u003cli\u003e\u0645\u062f\u0629 \u0627\u0644\u0628\u0631\u0646\u0627\u0645\u062c: \u0633\u0646\u062a\u0627\u0646.\u003c/li\u003e\u003cli\u003e\u0627\u0644\u0647\u062f\u0641: \u062a\u0632\u0648\u064a\u062f \u0627\u0644\u0637\u0644\u0627\u0628 \u0628\u0623\u0633\u0627\u0633 \u0642\u0648\u064a \u0641\u064a \u0627\u0644\u0630\u0643\u0627\u0621 \u0627\u0644\u0627\u0635\u0637\u0646\u0627\u0639\u064a.\u003c/li\u003e\u003c/ul\u003e\u003ch3\u003e\u003cstrong\u003e2. \u0627\u0644\u062f\u0643\u062a\u0648\u0631\u0627\u0647\u003c/strong\u003e:\u003c/h3\u003e\u003cul\u003e\u003cli\u003e\u0645\u062f\u0629 \u0627\u0644\u0628\u0631\u0646\u0627\u0645\u062c: \u0623\u0631\u0628\u0639 \u0633\u0646\u0648\u0627\u062a.\u003c/li\u003e\u003cli\u003e\u0627\u0644\u0647\u062f\u0641: \u062a\u0637\u0648\u064a\u0631 \u0627\u0644\u0645\u0647\u0627\u0631\u0627\u062a \u0627\u0644\u0628\u062d\u062b\u064a\u0629 \u0648\u0627\u0644\u0627\u0628\u062a\u0643\u0627\u0631\u064a\u0629 \u0644\u0645\u0648\u0627\u062c\u0647\u0629 \u062a\u062d\u062f\u064a\u0627\u062a \u0627\u0644\u0645\u0633\u062a\u0642\u0628\u0644.\u003c/li\u003e\u003c/ul\u003e\u003cp\u003e\u062a\u0642\u062f\u0645 \u0627\u0644\u0622\u0646: \u0645\u0646\u062d\u0629 \u062c\u0627\u0645\u0639\u0629 \u0642\u0637\u0631 \u0645\u0645\u0648\u0644\u0629 \u0628\u0627\u0644\u0643\u0627\u0645\u0644\u003c/p\u003e\u003ch2\u003e\u003cstrong\u003e\u0634\u0631\u0648\u0637 \u0627\u0644\u0642\u0628\u0648\u0644 \u0641\u064a \u0645\u0646\u062d\u0629 \u062c\u0627\u0645\u0639\u0629 \u0645\u062d\u0645\u062f \u0628\u0646 \u0632\u0627\u064a\u062f \u0644\u0644\u0630\u0643\u0627\u0621 \u0627\u0644\u0627\u0635\u0637\u0646\u0627\u0639\u064a:\u003c/strong\u003e\u003c/h2\u003e\u003cul\u003e\u003cli\u003e\u003cstrong\u003e\u0644\u0628\u0631\u0646\u0627\u0645\u062c \u0627\u0644\u0645\u0627\u062c\u0633\u062a\u064a\u0631\u003c/strong\u003e:\u003cul\u003e\u003cli\u003e\u062f\u0631\u062c\u0629 \u0627\u0644\u0628\u0643\u0627\u0644\u0648\u0631\u064a\u0648\u0633 \u0628\u062a\u0642\u062f\u064a\u0631 \u003cstrong\u003e\u062c\u064a\u062f \u062c\u062f\u064b\u0627\u003c/strong\u003e \u0643\u062d\u062f \u0623\u062f\u0646\u0649.\u003c/li\u003e\u003c/ul\u003e\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0644\u0628\u0631\u0646\u0627\u0645\u062c \u0627\u0644\u062f\u0643\u062a\u0648\u0631\u0627\u0647\u003c/strong\u003e:\u003cul\u003e\u003cli\u003e\u062f\u0631\u062c\u0629 \u0627\u0644\u0645\u0627\u062c\u0633\u062a\u064a\u0631 \u0641\u064a \u0627\u0644\u0639\u0644\u0648\u0645 \u0628\u062a\u0642\u062f\u064a\u0631 \u003cstrong\u003e\u0645\u0645\u062a\u0627\u0632\u003c/strong\u003e.\u003c/li\u003e\u003c/ul\u003e\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0645\u062a\u0637\u0644\u0628\u0627\u062a \u0625\u0636\u0627\u0641\u064a\u0629\u003c/strong\u003e:\u003cul\u003e\u003cli\u003e\u0634\u0647\u0627\u062f\u0629 \u0625\u062c\u0627\u062f\u0629 \u0627\u0644\u0644\u063a\u0629 \u0627\u0644\u0625\u0646\u062c\u0644\u064a\u0632\u064a\u0629 (TOEFL \u0623\u0648 IELTS).\u003c/li\u003e\u003cli\u003e\u0646\u062a\u0627\u0626\u062c GRE (\u0627\u062e\u062a\u064a\u0627\u0631\u064a \u0648\u0644\u0643\u0646 \u064a\u064f\u0641\u0636\u0644).\u003c/li\u003e\u003cli\u003e\u062e\u0644\u0641\u064a\u0629 \u0642\u0648\u064a\u0629 \u0641\u064a \u0627\u0644\u0631\u064a\u0627\u0636\u064a\u0627\u062a \u0648\u0627\u0644\u0628\u0631\u0645\u062c\u0629.\u003c/li\u003e\u003cli\u003e\u062e\u0628\u0631\u0629 \u0628\u062d\u062b\u064a\u0629 \u0623\u0648 \u0645\u0647\u0646\u064a\u0629 \u0641\u064a \u0645\u062c\u0627\u0644 \u0627\u0644\u0630\u0643\u0627\u0621 \u0627\u0644\u0627\u0635\u0637\u0646\u0627\u0639\u064a.\u003c/li\u003e\u003c/ul\u003e\u003c/li\u003e\u003c/ul\u003e\u003cp\u003e\u0625\u0644\u064a\u0643 \u0623\u064a\u0636\u0627\u064b: \u0645\u0646\u062d\u0629 \u062c\u0627\u0645\u0639\u0629 \u062d\u0645\u062f \u0628\u0646 \u062e\u0644\u064a\u0641\u0629 \u0645\u0645\u0648\u0644\u0629 \u0628\u0627\u0644\u0643\u0627\u0645\u0644\u003c/p\u003e\u003ch2\u003e\u003cstrong\u003e\u0645\u0648\u0627\u0639\u064a\u062f \u0627\u0644\u062a\u0642\u062f\u064a\u0645 \u0644\u0645\u0646\u062d\u0629 \u062c\u0627\u0645\u0639\u0629 \u0645\u062d\u0645\u062f \u0628\u0646 \u0632\u0627\u064a\u062f \u0644\u0644\u0630\u0643\u0627\u0621 \u0627\u0644\u0627\u0635\u0637\u0646\u0627\u0639\u064a:\u003c/strong\u003e\u003c/h2\u003e\u003cp\u003e\u0639\u0627\u062f\u0629\u064b \u0645\u0627 \u064a\u0628\u062f\u0623 \u0627\u0644\u062a\u0642\u062f\u064a\u0645 \u0644\u0644\u0645\u0646\u062d \u0627\u0644\u062f\u0631\u0627\u0633\u064a\u0629 \u0641\u064a \u062c\u0627\u0645\u0639\u0629 \u0645\u062d\u0645\u062f \u0628\u0646 \u0632\u0627\u064a\u062f \u0644\u0644\u0630\u0643\u0627\u0621 \u0627\u0644\u0627\u0635\u0637\u0646\u0627\u0639\u064a (MBZUAI) \u0641\u064a \u003cstrong\u003e\u0646\u0647\u0627\u064a\u0629 \u0627\u0644\u0639\u0627\u0645\u003c/strong\u003e\u060c \u0648\u064a\u0633\u062a\u0645\u0631 \u062d\u062a\u0649 27 \u0634\u0628\u0627\u0637 \u0645\u0646 \u0627\u0644\u0639\u0627\u0645 \u0627\u0644\u062a\u0627\u0644\u064a\u060c \u0628\u0627\u0644\u0646\u0633\u0628\u0629 \u0644\u0644\u0637\u0644\u0627\u0628 \u0627\u0644\u062f\u0648\u0644\u064a\u064a\u0646.\u0026nbsp;\u003c/p\u003e\u003cp\u003e\u064a\u062a\u0639\u064a\u0646 \u0639\u0644\u0649 \u0627\u0644\u0645\u062a\u0642\u062f\u0645\u064a\u0646 \u0625\u0631\u0633\u0627\u0644 \u0637\u0644\u0628\u0627\u062a\u0647\u0645 \u0642\u0628\u0644 \u0627\u0644\u0645\u0648\u0639\u062f \u0627\u0644\u0646\u0647\u0627\u0626\u064a \u0627\u0644\u0645\u062d\u062f\u062f\u060c \u0648\u0627\u0644\u0630\u064a \u064a\u0643\u0648\u0646 \u0639\u0627\u062f\u0629\u064b \u0641\u064a \u0634\u0647\u0631 27 \u0634\u0628\u0627\u0637 \u0645\u0646 \u0643\u0644 \u0639\u0627\u0645. \u0644\u0644\u062a\u0623\u0643\u062f \u0645\u0646 \u0645\u0648\u0627\u0639\u064a\u062f \u0627\u0644\u062a\u0642\u062f\u064a\u0645 \u0627\u0644\u062f\u0642\u064a\u0642\u0629\u060c \u064a\u0641\u0636\u0644 \u062f\u0627\u0626\u0645\u064b\u0627 \u0632\u064a\u0627\u0631\u0629 \u0627\u0644\u0645\u0648\u0642\u0639 \u0627\u0644\u0631\u0633\u0645\u064a \u0644\u0644\u062c\u0627\u0645\u0639\u0629 \u0623\u0648 \u0645\u062a\u0627\u0628\u0639\u0629 \u062a\u062d\u062f\u064a\u062b\u0627\u062a \u0628\u0648\u0627\u0628\u0629 \u0627\u0644\u062a\u0642\u062f\u064a\u0645 \u0627\u0644\u062e\u0627\u0635\u0629 \u0628\u0647\u0627.\u003c/p\u003e\u003cp\u003e\u062a\u0635\u0641\u062d \u0627\u0644\u0645\u0632\u064a\u062f: \u0645\u0646\u062d\u0629 \u062c\u0627\u0645\u0639\u0629 \u0644\u0648\u0633\u064a\u0644 \u0644\u0644\u062f\u0631\u0627\u0633\u0629 \u0641\u064a \u0642\u0637\u0631\u0026nbsp;\u003c/p\u003e\u003ch2\u003e\u003cstrong\u003e\u0634\u0631\u0648\u0637 \u0627\u0644\u062a\u0642\u062f\u064a\u0645 \u0644\u0645\u0646\u062d\u0629 \u062c\u0627\u0645\u0639\u0629 \u0645\u062d\u0645\u062f \u0628\u0646 \u0632\u0627\u064a\u062f \u0644\u0644\u0630\u0643\u0627\u0621 \u0627\u0644\u0627\u0635\u0637\u0646\u0627\u0639\u064a:\u003c/strong\u003e\u003c/h2\u003e\u003col\u003e\u003cli\u003e\u003cstrong\u003e\u0644\u0628\u0631\u0646\u0627\u0645\u062c \u0627\u0644\u0645\u0627\u062c\u0633\u062a\u064a\u0631\u003c/strong\u003e: \u064a\u062c\u0628 \u0623\u0646 \u064a\u0643\u0648\u0646 \u0627\u0644\u0645\u062a\u0642\u062f\u0645 \u062d\u0627\u0635\u0644\u0627\u064b \u0639\u0644\u0649 \u062f\u0631\u062c\u0629 \u0628\u0643\u0627\u0644\u0648\u0631\u064a\u0648\u0633 \u0628\u062a\u0642\u062f\u064a\u0631 \u0026quot;\u062c\u064a\u062f \u062c\u062f\u0627\u064b\u0026quot; \u0639\u0644\u0649 \u0627\u0644\u0623\u0642\u0644.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0644\u0628\u0631\u0646\u0627\u0645\u062c \u0627\u0644\u062f\u0643\u062a\u0648\u0631\u0627\u0647\u003c/strong\u003e: \u064a\u062c\u0628 \u0623\u0646 \u064a\u0643\u0648\u0646 \u0627\u0644\u0645\u062a\u0642\u062f\u0645 \u062d\u0627\u0635\u0644\u0627\u064b \u0639\u0644\u0649 \u062f\u0631\u062c\u0629 \u0645\u0627\u062c\u0633\u062a\u064a\u0631 \u0628\u062a\u0642\u062f\u064a\u0631 \u0026quot;\u0645\u0645\u062a\u0627\u0632\u0026quot;.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0625\u062c\u0627\u062f\u0629 \u0627\u0644\u0644\u063a\u0629 \u0627\u0644\u0625\u0646\u062c\u0644\u064a\u0632\u064a\u0629\u003c/strong\u003e: \u064a\u062a\u0639\u064a\u0646 \u0639\u0644\u0649 \u0627\u0644\u0645\u062a\u0642\u062f\u0645\u064a\u0646 \u062a\u0642\u062f\u064a\u0645 \u0634\u0647\u0627\u062f\u0629 TOEFL \u0623\u0648 IELTS \u0645\u0639 \u062f\u0631\u062c\u0627\u062a \u0645\u062d\u062f\u062f\u0629.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0627\u062e\u062a\u0628\u0627\u0631 GRE\u003c/strong\u003e: \u064a\u062c\u0628 \u062a\u0642\u062f\u064a\u0645 \u0646\u062a\u0627\u0626\u062c \u0627\u062e\u062a\u0628\u0627\u0631 GRE \u0628\u062f\u0631\u062c\u0627\u062a \u062a\u0646\u0627\u0641\u0633\u064a\u0629.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u062e\u0644\u0641\u064a\u0629 \u0623\u0643\u0627\u062f\u064a\u0645\u064a\u0629\u003c/strong\u003e: \u064a\u062c\u0628 \u0623\u0646 \u064a\u0645\u062a\u0644\u0643 \u0627\u0644\u0645\u062a\u0642\u062f\u0645 \u062e\u0644\u0641\u064a\u0629 \u0642\u0648\u064a\u0629 \u0641\u064a \u0627\u0644\u0631\u064a\u0627\u0636\u064a\u0627\u062a \u0648\u0627\u0644\u0628\u0631\u0645\u062c\u0629.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0627\u0644\u062e\u0628\u0631\u0629 \u0627\u0644\u0628\u062d\u062b\u064a\u0629\u003c/strong\u003e: \u064a\u0641\u0636\u0644 \u0644\u0644\u0645\u062a\u0642\u062f\u0645\u064a\u0646 \u0644\u0628\u0631\u0646\u0627\u0645\u062c \u0627\u0644\u062f\u0643\u062a\u0648\u0631\u0627\u0647 \u0623\u0646 \u064a\u0643\u0648\u0646 \u0644\u062f\u064a\u0647\u0645 \u062e\u0628\u0631\u0629 \u0628\u062d\u062b\u064a\u0629 \u0623\u0648 \u0639\u0645\u0644\u064a\u0629 \u0641\u064a \u0645\u062c\u0627\u0644 \u0627\u0644\u0630\u0643\u0627\u0621 \u0627\u0644\u0627\u0635\u0637\u0646\u0627\u0639\u064a.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0627\u0644\u0645\u0642\u0627\u0628\u0644\u0629 \u0627\u0644\u0634\u062e\u0635\u064a\u0629\u003c/strong\u003e: \u064a\u062c\u0628 \u0627\u062c\u062a\u064a\u0627\u0632 \u0627\u0644\u0645\u0642\u0627\u0628\u0644\u0629 \u0627\u0644\u0634\u062e\u0635\u064a\u0629 \u0627\u0644\u062a\u064a \u062a\u062c\u0631\u064a\u0647\u0627 \u0644\u062c\u0646\u0629 \u0627\u0644\u0642\u0628\u0648\u0644 \u0628\u0627\u0644\u062c\u0627\u0645\u0639\u0629.\u003c/li\u003e\u003c/ol\u003e\u003cp\u003e\u0625\u0644\u064a\u0643 \u0627\u0644\u0622\u0646: \u0645\u0646\u062d\u0629 \u0645\u0639\u0647\u062f \u0627\u0644\u062f\u0648\u062d\u0629 \u0644\u0644\u062f\u0631\u0627\u0633\u0627\u062a \u0627\u0644\u0639\u0644\u064a\u0627 \u0641\u064a \u0642\u0637\u0631\u0026nbsp;\u003c/p\u003e\u003ch2\u003e\u003cstrong\u003e\u0627\u0644\u0623\u0648\u0631\u0627\u0642 \u0627\u0644\u0645\u0637\u0644\u0648\u0628\u0629 \u0644\u0645\u0646\u062d\u0629 \u062c\u0627\u0645\u0639\u0629 \u0645\u062d\u0645\u062f \u0628\u0646 \u0632\u0627\u064a\u062f \u0644\u0644\u0630\u0643\u0627\u0621 \u0627\u0644\u0627\u0635\u0637\u0646\u0627\u0639\u064a:\u003c/strong\u003e\u003c/h2\u003e\u003cul\u003e\u003cli\u003e\u0646\u0633\u062e\u0629 \u0645\u0646 \u062c\u0648\u0627\u0632 \u0627\u0644\u0633\u0641\u0631.\u003c/li\u003e\u003cli\u003e\u0627\u0644\u0634\u0647\u0627\u062f\u0627\u062a \u0627\u0644\u0623\u0643\u0627\u062f\u064a\u0645\u064a\u0629 \u0648\u0643\u0634\u0648\u0641 \u0627\u0644\u062f\u0631\u062c\u0627\u062a.\u003c/li\u003e\u003cli\u003e\u0634\u0647\u0627\u062f\u0629 \u0625\u062c\u0627\u062f\u0629 \u0627\u0644\u0644\u063a\u0629 \u0627\u0644\u0625\u0646\u062c\u0644\u064a\u0632\u064a\u0629.\u003c/li\u003e\u003cli\u003e\u0627\u0644\u0633\u064a\u0631\u0629 \u0627\u0644\u0630\u0627\u062a\u064a\u0629 \u0645\u062d\u062f\u062b\u0629.\u003c/li\u003e\u003cli\u003e\u062e\u0637\u0627\u0628 \u062a\u062d\u0641\u064a\u0632\u064a \u064a\u0648\u0636\u062d \u0623\u0633\u0628\u0627\u0628 \u0627\u0644\u062a\u0642\u062f\u064a\u0645.\u003c/li\u003e\u003cli\u003e\u062b\u0644\u0627\u062b \u0631\u0633\u0627\u0626\u0644 \u062a\u0648\u0635\u064a\u0629 \u0645\u0646 \u0623\u0643\u0627\u062f\u064a\u0645\u064a\u064a\u0646 \u0623\u0648 \u0645\u0647\u0646\u064a\u064a\u0646.\u003c/li\u003e\u003cli\u003e\u0627\u0642\u062a\u0631\u0627\u062d \u0628\u062d\u062b (\u0644\u0644\u0645\u062a\u0642\u062f\u0645\u064a\u0646 \u0644\u0644\u062f\u0643\u062a\u0648\u0631\u0627\u0647).\u003c/li\u003e\u003c/ul\u003e\u003cblockquote\u003e\u003cp\u003e\u0645\u0644\u062d\u0648\u0638\u0629: \u064a\u062c\u0628 \u062a\u0631\u062c\u0645\u0629 \u0627\u0644\u0634\u0647\u0627\u062f\u0627\u062a \u063a\u064a\u0631 \u0627\u0644\u0635\u0627\u062f\u0631\u0629 \u0628\u0627\u0644\u0644\u063a\u0629 \u0627\u0644\u0625\u0646\u062c\u0644\u064a\u0632\u064a\u0629 \u0625\u0644\u0649 \u0627\u0644\u0625\u0646\u062c\u0644\u064a\u0632\u064a\u0629 \u0648\u062a\u0635\u062f\u064a\u0642\u0647\u0627 \u0645\u0646 \u0627\u0644\u062c\u0647\u0627\u062a \u0627\u0644\u0645\u0639\u0646\u064a\u0629.\u003c/p\u003e\u003c/blockquote\u003e\u003c/div\u003e\u003c/div\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cbr\u003e\u003c/div\u003e\u003cdiv\u003e\u003cp\u003e\u0625\u0644\u064a\u0643 \u0627\u0644\u0645\u0632\u064a\u062f: \u0645\u0646\u062d\u0629 \u0627\u0644\u062d\u0643\u0648\u0645\u0629 \u0627\u0644\u062a\u0631\u0643\u064a\u0629\u003c/p\u003e\u003ch2\u003e\u003cstrong\u003e\u0643\u064a\u0641\u064a\u0629 \u0627\u0644\u062a\u0642\u062f\u064a\u0645 \u0639\u0644\u0649 \u0645\u0646\u062d\u0629 \u062c\u0627\u0645\u0639\u0629 \u0645\u062d\u0645\u062f \u0628\u0646 \u0632\u0627\u064a\u062f \u0644\u0644\u0630\u0643\u0627\u0621 \u0627\u0644\u0627\u0635\u0637\u0646\u0627\u0639\u064a\u061f\u003c/strong\u003e\u003c/h2\u003e\u003col\u003e\u003cli\u003e\u003cstrong\u003e\u0632\u064a\u0627\u0631\u0629 \u0627\u0644\u0645\u0648\u0642\u0639 \u0627\u0644\u0631\u0633\u0645\u064a\u003c/strong\u003e \u0644\u062c\u0627\u0645\u0639\u0629 \u0645\u062d\u0645\u062f \u0628\u0646 \u0632\u0627\u064a\u062f \u0644\u0644\u0630\u0643\u0627\u0621 \u0627\u0644\u0627\u0635\u0637\u0646\u0627\u0639\u064a.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0625\u0646\u0634\u0627\u0621 \u062d\u0633\u0627\u0628\u003c/strong\u003e \u0639\u0644\u0649 \u0628\u0648\u0627\u0628\u0629 \u0627\u0644\u062a\u0642\u062f\u064a\u0645.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0645\u0644\u0621 \u0646\u0645\u0648\u0630\u062c \u0627\u0644\u0637\u0644\u0628\u003c/strong\u003e \u0628\u062f\u0642\u0629.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0631\u0641\u0639 \u0627\u0644\u0648\u062b\u0627\u0626\u0642 \u0627\u0644\u0645\u0637\u0644\u0648\u0628\u0629\u003c/strong\u003e \u0648\u0627\u0644\u062a\u0623\u0643\u062f \u0645\u0646 \u062c\u0648\u062f\u062a\u0647\u0627.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0625\u0631\u0633\u0627\u0644 \u0627\u0644\u0637\u0644\u0628\u003c/strong\u003e \u0642\u0628\u0644 \u0627\u0644\u0645\u0648\u0639\u062f \u0627\u0644\u0646\u0647\u0627\u0626\u064a.\u003c/li\u003e\u003c/ol\u003e\u003ch2\u003e\u003cstrong\u003e\u0641\u0631\u0635 \u0627\u0644\u062a\u062f\u0631\u064a\u0628 \u0648\u0627\u0644\u0628\u062d\u062b \u0641\u064a \u062c\u0627\u0645\u0639\u0629 \u0645\u062d\u0645\u062f \u0628\u0646 \u0632\u0627\u064a\u062f \u0644\u0644\u0630\u0643\u0627\u0621 \u0627\u0644\u0627\u0635\u0637\u0646\u0627\u0639\u064a\u003c/strong\u003e\u003c/h2\u003e\u003cul\u003e\u003cli\u003e\u003cstrong\u003e\u0634\u0631\u0627\u0643\u0627\u062a \u0639\u0627\u0644\u0645\u064a\u0629:\u003c/strong\u003e \u062a\u0648\u0641\u0631 \u0627\u0644\u062c\u0627\u0645\u0639\u0629 \u0641\u0631\u0635 \u062a\u0639\u0627\u0648\u0646 \u0645\u0639 \u0643\u0628\u0631\u0649 \u0627\u0644\u0634\u0631\u0643\u0627\u062a \u0627\u0644\u0639\u0627\u0644\u0645\u064a\u0629 \u0645\u062b\u0644 Google \u0648Microsoft.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0645\u0634\u0627\u0631\u064a\u0639 \u062d\u0642\u064a\u0642\u064a\u0629:\u003c/strong\u003e \u064a\u0634\u0627\u0631\u0643 \u0627\u0644\u0637\u0644\u0627\u0628 \u0641\u064a \u0623\u0628\u062d\u0627\u062b \u0648\u062a\u0637\u0628\u064a\u0642\u0627\u062a \u0639\u0645\u0644\u064a\u0629 \u062a\u0633\u0627\u0639\u062f\u0647\u0645 \u0639\u0644\u0649 \u0627\u0643\u062a\u0633\u0627\u0628 \u062e\u0628\u0631\u0629 \u062d\u0642\u064a\u0642\u064a\u0629.\u003c/li\u003e\u003c/ul\u003e\u003ch2\u003e\u003cstrong\u003e\u0646\u0635\u0627\u0626\u062d \u0644\u0644\u062a\u0642\u062f\u064a\u0645 \u0627\u0644\u0646\u0627\u062c\u062d\u003c/strong\u003e\u003c/h2\u003e\u003cul\u003e\u003cli\u003e\u0631\u0643\u0632 \u0641\u064a \u062e\u0637\u0627\u0628 \u0627\u0644\u0646\u064a\u0629 \u0639\u0644\u0649 \u0623\u0647\u062f\u0627\u0641\u0643 \u0627\u0644\u0645\u0633\u062a\u0642\u0628\u0644\u064a\u0629 \u0648\u0634\u063a\u0641\u0643 \u0628\u0627\u0644\u0630\u0643\u0627\u0621 \u0627\u0644\u0627\u0635\u0637\u0646\u0627\u0639\u064a.\u003c/li\u003e\u003cli\u003e\u0627\u0633\u062a\u0639\u062f \u062c\u064a\u062f\u0627\u064b \u0644\u0644\u0645\u0642\u0627\u0628\u0644\u0629 \u0627\u0644\u0634\u062e\u0635\u064a\u0629.\u003c/li\u003e\u003cli\u003e\u062a\u062d\u0642\u0642 \u0645\u0646 \u062c\u0648\u062f\u0629 \u0648\u062f\u0642\u0629 \u062c\u0645\u064a\u0639 \u0627\u0644\u0648\u062b\u0627\u0626\u0642 \u0627\u0644\u0645\u0642\u062f\u0645\u0629.\u003c/li\u003e\u003c/ul\u003e\u003ch3\u003e\u003cstrong\u003e\u0645\u0627\u0630\u0627 \u0628\u0639\u062f \u0627\u0644\u0642\u0628\u0648\u0644\u061f\u003c/strong\u003e\u003c/h3\u003e\u003cul\u003e\u003cli\u003e\u0633\u062a\u062a\u0644\u0642\u0649 \u062e\u0637\u0629 \u062f\u0631\u0627\u0633\u064a\u0629 \u0645\u0641\u0635\u0644\u0629.\u003c/li\u003e\u003cli\u003e\u064a\u0645\u0643\u0646\u0643 \u0627\u0644\u062a\u0648\u0627\u0635\u0644 \u0645\u0639 \u0645\u0633\u062a\u0634\u0627\u0631 \u0623\u0643\u0627\u062f\u064a\u0645\u064a \u0644\u062a\u062d\u062f\u064a\u062f \u0623\u0647\u062f\u0627\u0641\u0643 \u0627\u0644\u0623\u0643\u0627\u062f\u064a\u0645\u064a\u0629.\u003c/li\u003e\u003cli\u003e\u0633\u062a\u062a\u0627\u062d \u0644\u0643 \u0627\u0644\u0645\u0634\u0627\u0631\u0643\u0629 \u0641\u064a \u0645\u0624\u062a\u0645\u0631\u0627\u062a \u0639\u0644\u0645\u064a\u0629 \u0648\u0627\u0644\u062a\u062f\u0631\u064a\u0628 \u0645\u0639 \u0634\u0631\u0643\u0627\u062a \u0639\u0627\u0644\u0645\u064a\u0629.\u003c/li\u003e\u003c/ul\u003e\u003ch2\u003e\u003cstrong\u003e\u0646\u0628\u0630\u0629 \u0639\u0646 \u062c\u0627\u0645\u0639\u0629 \u0645\u062d\u0645\u062f \u0628\u0646 \u0632\u0627\u064a\u062f \u0644\u0644\u0630\u0643\u0627\u0621 \u0627\u0644\u0627\u0635\u0637\u0646\u0627\u0639\u064a\u003c/strong\u003e\u003c/h2\u003e\u003cp\u003e\u062a\u0623\u0633\u0633\u062a \u062c\u0627\u0645\u0639\u0629 \u0645\u062d\u0645\u062f \u0628\u0646 \u0632\u0627\u064a\u062f \u0641\u064a \u0639\u0627\u0645 2026 \u0643\u0623\u0648\u0644 \u062c\u0627\u0645\u0639\u0629 \u0644\u0644\u062f\u0631\u0627\u0633\u0627\u062a \u0627\u0644\u0639\u0644\u064a\u0627 \u0627\u0644\u0645\u062a\u062e\u0635\u0635\u0629 \u0641\u064a \u0623\u0628\u062d\u0627\u062b \u0627\u0644\u0630\u0643\u0627\u0621 \u0627\u0644\u0627\u0635\u0637\u0646\u0627\u0639\u064a. \u062a\u0647\u062f\u0641 \u0627\u0644\u062c\u0627\u0645\u0639\u0629 \u0625\u0644\u0649 \u062a\u0639\u0632\u064a\u0632 \u0645\u0643\u0627\u0646\u0629 \u0627\u0644\u0625\u0645\u0627\u0631\u0627\u062a \u0643\u0645\u0631\u0643\u0632 \u0639\u0627\u0644\u0645\u064a \u0644\u0644\u0627\u0628\u062a\u0643\u0627\u0631 \u0641\u064a \u0647\u0630\u0627 \u0627\u0644\u0645\u062c\u0627\u0644 \u0627\u0644\u062d\u064a\u0648\u064a.\u003cbr\u003e\u062a\u062a\u0645\u064a\u0632 \u0627\u0644\u062c\u0627\u0645\u0639\u0629 \u0628\u0645\u0627 \u064a\u0644\u064a:\u003c/p\u003e\u003cul\u003e\u003cli\u003e\u0628\u064a\u0626\u0629 \u062a\u0639\u0644\u064a\u0645\u064a\u0629 \u0645\u0628\u062a\u0643\u0631\u0629 \u0645\u062c\u0647\u0632\u0629 \u0628\u0623\u062d\u062f\u062b \u0627\u0644\u062a\u0642\u0646\u064a\u0627\u062a.\u003c/li\u003e\u003cli\u003e\u0646\u062e\u0628\u0629 \u0645\u0646 \u0627\u0644\u0623\u0643\u0627\u062f\u064a\u0645\u064a\u064a\u0646 \u0648\u0627\u0644\u0628\u0627\u062d\u062b\u064a\u0646 \u0627\u0644\u062f\u0648\u0644\u064a\u064a\u0646 \u0641\u064a \u0627\u0644\u0630\u0643\u0627\u0621 \u0627\u0644\u0627\u0635\u0637\u0646\u0627\u0639\u064a.\u003c/li\u003e\u003cli\u003e\u062a\u0631\u0643\u064a\u0632 \u0639\u0644\u0649 \u062b\u0644\u0627\u062b\u0629 \u0645\u062c\u0627\u0644\u0627\u062a \u0631\u0626\u064a\u0633\u064a\u0629: \u003cstrong\u003e\u0627\u0644\u0631\u0624\u064a\u0629 \u0627\u0644\u062d\u0627\u0633\u0648\u0628\u064a\u0629\u003c/strong\u003e\u060c \u003cstrong\u003e\u062a\u0639\u0644\u0645 \u0627\u0644\u0622\u0644\u0629\u003c/strong\u003e\u060c \u0648\u003cstrong\u003e\u0645\u0639\u0627\u0644\u062c\u0629 \u0627\u0644\u0644\u063a\u0627\u062a \u0627\u0644\u0637\u0628\u064a\u0639\u064a\u0629\u003c/strong\u003e.\u003c/li\u003e\u003c/ul\u003e\u003cp\u003e\u0625\u0644\u064a\u0643 \u0623\u064a\u0636\u0627\u064b: \u0645\u0646\u062d\u0629 \u062c\u0627\u0645\u0639\u0629 \u062f\u0627\u064a\u062a\u0648\u0646 \u0644\u0644\u062f\u0631\u0627\u0633\u0629 \u0641\u064a \u0627\u0644\u0648\u0644\u0627\u064a\u0627\u062a \u0627\u0644\u0645\u062a\u062d\u062f\u0629 \u0627\u0644\u0623\u0645\u0631\u064a\u0643\u064a\u0629\u003c/p\u003e\u003cp\u003e\u003cbr\u003e\u003c/p\u003e\u003ch2\u003e\u003cstrong\u003e* \u0623\u0633\u0626\u0644\u0629 \u0634\u0627\u0626\u0639\u0629 \u062d\u0648\u0644 \u0645\u0646\u062d\u0629 \u062c\u0627\u0645\u0639\u0629 \u0645\u062d\u0645\u062f \u0628\u0646 \u0632\u0627\u064a\u062f \u0644\u0644\u0630\u0643\u0627\u0621 \u0627\u0644\u0627\u0635\u0637\u0646\u0627\u0639\u064a:\u003c/strong\u003e\u003c/h2\u003e\u003col\u003e\u003cli\u003e\u003cp\u003e\u003cstrong\u003e\u0645\u0627 \u0647\u064a \u0645\u0646\u062d\u0629 \u062c\u0627\u0645\u0639\u0629 \u0645\u062d\u0645\u062f \u0628\u0646 \u0632\u0627\u064a\u062f \u0644\u0644\u0630\u0643\u0627\u0621 \u0627\u0644\u0627\u0635\u0637\u0646\u0627\u0639\u064a\u061f\u003c/strong\u003e\u003cbr\u003e\u0647\u064a \u0645\u0646\u062d\u0629 \u062f\u0631\u0627\u0633\u064a\u0629 \u0645\u0645\u0648\u0644\u0629 \u0628\u0627\u0644\u0643\u0627\u0645\u0644 \u0644\u062f\u0631\u0627\u0633\u0629 \u0627\u0644\u0645\u0627\u062c\u0633\u062a\u064a\u0631 \u0623\u0648 \u0627\u0644\u062f\u0643\u062a\u0648\u0631\u0627\u0647 \u0641\u064a \u0645\u062c\u0627\u0644 \u0627\u0644\u0630\u0643\u0627\u0621 \u0627\u0644\u0627\u0635\u0637\u0646\u0627\u0639\u064a \u0641\u064a \u062c\u0627\u0645\u0639\u0629 \u0645\u062d\u0645\u062f \u0628\u0646 \u0632\u0627\u064a\u062f \u0641\u064a \u0623\u0628\u0648\u0638\u0628\u064a. \u062a\u0645\u0646\u062d \u0647\u0630\u0647 \u0627\u0644\u0645\u0646\u062d\u0629 \u0627\u0644\u0637\u0644\u0627\u0628 \u062f\u0631\u0627\u0633\u0629 \u0641\u064a \u0628\u064a\u0626\u0629 \u062a\u0639\u0644\u064a\u0645\u064a\u0629 \u0645\u0628\u062a\u0643\u0631\u0629 \u0648\u0645\u062a\u0637\u0648\u0631\u0629.\u003c/p\u003e\u003c/li\u003e\u003cli\u003e\u003cp\u003e\u003cstrong\u003e\u0645\u0627 \u0647\u064a \u0645\u0632\u0627\u064a\u0627 \u0627\u0644\u0645\u0646\u062d\u0629\u061f\u003c/strong\u003e\u003cbr\u003e\u062a\u0634\u0645\u0644 \u0627\u0644\u0645\u0646\u062d\u0629 \u0627\u0644\u0631\u0633\u0648\u0645 \u0627\u0644\u062f\u0631\u0627\u0633\u064a\u0629 \u0627\u0644\u0645\u062c\u0627\u0646\u064a\u0629\u060c \u0631\u0627\u062a\u0628 \u0634\u0647\u0631\u064a \u0645\u063a\u0631\u064a\u060c \u0633\u0643\u0646 \u0645\u062c\u0627\u0646\u064a \u062f\u0627\u062e\u0644 \u0627\u0644\u062d\u0631\u0645 \u0627\u0644\u062c\u0627\u0645\u0639\u064a\u060c \u062a\u0623\u0645\u064a\u0646 \u0635\u062d\u064a \u0634\u0627\u0645\u0644\u060c \u0648\u062a\u063a\u0637\u064a\u0629 \u062a\u0643\u0627\u0644\u064a\u0641 \u0627\u0644\u0643\u062a\u0628 \u0648\u0627\u0644\u0645\u0648\u0627\u062f \u0627\u0644\u062f\u0631\u0627\u0633\u064a\u0629. \u0643\u0645\u0627 \u064a\u062d\u0635\u0644 \u0627\u0644\u0637\u0644\u0627\u0628 \u0627\u0644\u062f\u0648\u0644\u064a\u0648\u0646 \u0639\u0644\u0649 \u062a\u0630\u0627\u0643\u0631 \u0633\u0641\u0631 \u0633\u0646\u0648\u064a\u0629.\u003c/p\u003e\u003c/li\u003e\u003cli\u003e\u003cp\u003e\u003cstrong\u003e\u0645\u0627 \u0647\u064a \u0627\u0644\u0634\u0631\u0648\u0637 \u0627\u0644\u0645\u0637\u0644\u0648\u0628\u0629 \u0644\u0644\u062a\u0642\u062f\u064a\u0645\u061f\u003c/strong\u003e\u003cbr\u003e\u064a\u062c\u0628 \u0639\u0644\u0649 \u0627\u0644\u0645\u062a\u0642\u062f\u0645\u064a\u0646 \u0644\u0628\u0631\u0646\u0627\u0645\u062c \u0627\u0644\u0645\u0627\u062c\u0633\u062a\u064a\u0631 \u0623\u0646 \u064a\u0643\u0648\u0646\u0648\u0627 \u062d\u0627\u0635\u0644\u064a\u0646 \u0639\u0644\u0649 \u062f\u0631\u062c\u0629 \u0628\u0643\u0627\u0644\u0648\u0631\u064a\u0648\u0633 \u0628\u062a\u0642\u062f\u064a\u0631 \u0026quot;\u062c\u064a\u062f \u062c\u062f\u0627\u064b\u0026quot; \u0639\u0644\u0649 \u0627\u0644\u0623\u0642\u0644\u060c \u0648\u0644\u0628\u0631\u0646\u0627\u0645\u062c \u0627\u0644\u062f\u0643\u062a\u0648\u0631\u0627\u0647 \u064a\u062c\u0628 \u0623\u0646 \u064a\u0643\u0648\u0646 \u0627\u0644\u0645\u062a\u0642\u062f\u0645 \u062d\u0627\u0635\u0644\u0627\u064b \u0639\u0644\u0649 \u062f\u0631\u062c\u0629 \u0645\u0627\u062c\u0633\u062a\u064a\u0631 \u0628\u062a\u0642\u062f\u064a\u0631 \u0026quot;\u0645\u0645\u062a\u0627\u0632\u0026quot;. \u0628\u0627\u0644\u0625\u0636\u0627\u0641\u0629 \u0625\u0644\u0649 \u0630\u0644\u0643\u060c \u064a\u062c\u0628 \u062a\u0642\u062f\u064a\u0645 \u0634\u0647\u0627\u062f\u0629 \u0625\u062c\u0627\u062f\u0629 \u0627\u0644\u0644\u063a\u0629 \u0627\u0644\u0625\u0646\u062c\u0644\u064a\u0632\u064a\u0629 (TOEFL \u0623\u0648 IELTS)\u060c \u0648\u064a\u0641\u0636\u0644 \u062a\u0642\u062f\u064a\u0645 \u0646\u062a\u0627\u0626\u062c GRE.\u003c/p\u003e\u003c/li\u003e\u003cli\u003e\u003cp\u003e\u003cstrong\u003e\u0645\u0627 \u0647\u064a \u0627\u0644\u0623\u0648\u0631\u0627\u0642 \u0627\u0644\u0645\u0637\u0644\u0648\u0628\u0629 \u0644\u0644\u062a\u0642\u062f\u064a\u0645\u061f\u003c/strong\u003e\u003cbr\u003e\u062a\u0634\u0645\u0644 \u0627\u0644\u0623\u0648\u0631\u0627\u0642 \u0627\u0644\u0645\u0637\u0644\u0648\u0628\u0629 \u0646\u0633\u062e\u0629 \u0645\u0646 \u062c\u0648\u0627\u0632 \u0627\u0644\u0633\u0641\u0631\u060c \u0627\u0644\u0634\u0647\u0627\u062f\u0627\u062a \u0627\u0644\u0623\u0643\u0627\u062f\u064a\u0645\u064a\u0629\u060c \u0634\u0647\u0627\u062f\u0629 \u0625\u062c\u0627\u062f\u0629 \u0627\u0644\u0644\u063a\u0629 \u0627\u0644\u0625\u0646\u062c\u0644\u064a\u0632\u064a\u0629\u060c \u0627\u0644\u0633\u064a\u0631\u0629 \u0627\u0644\u0630\u0627\u062a\u064a\u0629\u060c \u062e\u0637\u0627\u0628 \u062a\u062d\u0641\u064a\u0632\u064a\u060c \u0631\u0633\u0627\u0626\u0644 \u062a\u0648\u0635\u064a\u0629\u060c \u0648\u0627\u0642\u062a\u0631\u0627\u062d \u0628\u062d\u062b (\u0644\u0644\u0645\u062a\u0642\u062f\u0645\u064a\u0646 \u0644\u0628\u0631\u0646\u0627\u0645\u062c \u0627\u0644\u062f\u0643\u062a\u0648\u0631\u0627\u0647).\u003c/p\u003e\u003c/li\u003e\u003cli\u003e\u003cp\u003e\u003cstrong\u003e\u0643\u064a\u0641 \u064a\u0645\u0643\u0646 \u0627\u0644\u062a\u0642\u062f\u064a\u0645 \u0644\u0644\u0645\u0646\u062d\u0629\u061f\u003c/strong\u003e\u003cbr\u003e\u064a\u062c\u0628 \u0632\u064a\u0627\u0631\u0629 \u0627\u0644\u0645\u0648\u0642\u0639 \u0627\u0644\u0631\u0633\u0645\u064a \u0644\u0644\u062c\u0627\u0645\u0639\u0629 \u0648\u0625\u0646\u0634\u0627\u0621 \u062d\u0633\u0627\u0628 \u0639\u0644\u0649 \u0628\u0648\u0627\u0628\u0629 \u0627\u0644\u062a\u0642\u062f\u064a\u0645. \u0628\u0639\u062f\u0647\u0627\u060c \u064a\u062a\u0645 \u0645\u0644\u0621 \u0646\u0645\u0648\u0630\u062c \u0627\u0644\u0637\u0644\u0628 \u0648\u0631\u0641\u0639 \u0627\u0644\u0648\u062b\u0627\u0626\u0642 \u0627\u0644\u0645\u0637\u0644\u0648\u0628\u0629 \u0642\u0628\u0644 \u0627\u0644\u0645\u0648\u0639\u062f \u0627\u0644\u0646\u0647\u0627\u0626\u064a.\u003c/p\u003e\u003c/li\u003e\u003cli\u003e\u003cp\u003e\u003cstrong\u003e\u0645\u0627 \u0647\u064a \u0645\u0648\u0627\u0639\u064a\u062f \u0627\u0644\u062a\u0642\u062f\u064a\u0645 \u0644\u0644\u0645\u0646\u062d\u0629\u061f\u003c/strong\u003e\u003cbr\u003e\u064a\u0628\u062f\u0623 \u0627\u0644\u062a\u0642\u062f\u064a\u0645 \u0639\u0627\u062f\u0629 \u0641\u064a \u0646\u0647\u0627\u064a\u0629 \u0627\u0644\u0639\u0627\u0645 \u0648\u064a\u0633\u062a\u0645\u0631 \u062d\u062a\u0649 27 \u0634\u0628\u0627\u0637 \u0645\u0646 \u0627\u0644\u0639\u0627\u0645 \u0627\u0644\u062a\u0627\u0644\u064a. \u064a\u0646\u0635\u062d \u0628\u0645\u0631\u0627\u062c\u0639\u0629 \u0627\u0644\u0645\u0648\u0642\u0639 \u0627\u0644\u0631\u0633\u0645\u064a \u0644\u0644\u062c\u0627\u0645\u0639\u0629 \u0644\u0644\u062d\u0635\u0648\u0644 \u0639\u0644\u0649 \u0627\u0644\u062a\u0648\u0627\u0631\u064a\u062e \u0627\u0644\u062f\u0642\u064a\u0642\u0629.\u003c/p\u003e\u003c/li\u003e\u003cli\u003e\u003cp\u003e\u003cstrong\u003e\u0647\u0644 \u062a\u0648\u062c\u062f \u0641\u0631\u0635 \u062a\u062f\u0631\u064a\u0628 \u0623\u0648 \u0628\u062d\u062b\u061f\u003c/strong\u003e\u003cbr\u003e\u062a\u0648\u0641\u0631 \u0627\u0644\u062c\u0627\u0645\u0639\u0629 \u0641\u0631\u0635 \u062a\u062f\u0631\u064a\u0628\u064a\u0629 \u0628\u0627\u0644\u062a\u0639\u0627\u0648\u0646 \u0645\u0639 \u0634\u0631\u0643\u0627\u062a \u0639\u0627\u0644\u0645\u064a\u0629 \u0645\u062b\u0644 Google \u0648Microsoft. \u0643\u0645\u0627 \u064a\u0634\u0627\u0631\u0643 \u0627\u0644\u0637\u0644\u0627\u0628 \u0641\u064a \u0623\u0628\u062d\u0627\u062b \u062a\u0637\u0628\u064a\u0642\u064a\u0629 \u062a\u0632\u064a\u062f \u0645\u0646 \u062e\u0628\u0631\u062a\u0647\u0645 \u0627\u0644\u0639\u0645\u0644\u064a\u0629.\u003c/p\u003e\u003c/li\u003e\u003cli\u003e\u003cp\u003e\u003cstrong\u003e\u0645\u0627\u0630\u0627 \u064a\u062d\u062f\u062b \u0628\u0639\u062f \u0627\u0644\u0642\u0628\u0648\u0644\u061f\u003c/strong\u003e\u003cbr\u003e\u0633\u064a\u062d\u0635\u0644 \u0627\u0644\u0637\u0644\u0627\u0628 \u0627\u0644\u0645\u0642\u0628\u0648\u0644\u0648\u0646 \u0639\u0644\u0649 \u062e\u0637\u0629 \u062f\u0631\u0627\u0633\u064a\u0629 \u0645\u0641\u0635\u0644\u0629 \u0648\u0633\u064a\u062a\u0648\u0627\u0635\u0644\u0648\u0646 \u0645\u0639 \u0645\u0633\u062a\u0634\u0627\u0631 \u0623\u0643\u0627\u062f\u064a\u0645\u064a \u0644\u0645\u0633\u0627\u0639\u062f\u062a\u0647\u0645 \u0641\u064a \u062a\u062d\u062f\u064a\u062f \u0623\u0647\u062f\u0627\u0641\u0647\u0645 \u0627\u0644\u0623\u0643\u0627\u062f\u064a\u0645\u064a\u0629. \u0633\u064a\u062a\u0645\u0643\u0646\u0648\u0646 \u0645\u0646 \u0627\u0644\u0645\u0634\u0627\u0631\u0643\u0629 \u0641\u064a \u0645\u0624\u062a\u0645\u0631\u0627\u062a \u0639\u0644\u0645\u064a\u0629 \u0648\u0627\u0644\u062a\u062f\u0631\u064a\u0628 \u0645\u0639 \u0634\u0631\u0643\u0627\u062a \u0639\u0627\u0644\u0645\u064a\u0629.\u003c/p\u003e\u003c/li\u003e\u003cli\u003e\u003cp\u003e\u003cstrong\u003e\u0647\u0644 \u062a\u0648\u062c\u062f \u0641\u0631\u0635 \u0644\u0644\u0637\u0644\u0627\u0628 \u0627\u0644\u0625\u0645\u0627\u0631\u0627\u062a\u064a\u064a\u0646\u061f\u003c/strong\u003e\u003cbr\u003e\u0646\u0639\u0645\u060c \u064a\u062a\u0645 \u062a\u0642\u062f\u064a\u0645 \u0631\u0627\u062a\u0628 \u0634\u0647\u0631\u064a \u0642\u062f\u0631\u0647 36,000 \u062f\u0631\u0647\u0645 \u0644\u0644\u0637\u0644\u0627\u0628 \u0627\u0644\u0625\u0645\u0627\u0631\u0627\u062a\u064a\u064a\u0646 \u0628\u0627\u0644\u0625\u0636\u0627\u0641\u0629 \u0625\u0644\u0649 \u0627\u0644\u0645\u0632\u0627\u064a\u0627 \u0627\u0644\u0623\u062e\u0631\u0649.\u003c/p\u003e\u003c/li\u003e\u003cli\u003e\u003cp\u003e\u003cstrong\u003e\u0647\u0644 \u0627\u0644\u0645\u0646\u062d\u0629 \u062a\u0634\u0645\u0644 \u0627\u0644\u0637\u0644\u0627\u0628 \u0627\u0644\u062f\u0648\u0644\u064a\u064a\u0646\u061f\u003c/strong\u003e\u003cbr\u003e\u0646\u0639\u0645\u060c \u0627\u0644\u0645\u0646\u062d\u0629 \u0645\u062a\u0627\u062d\u0629 \u0644\u0644\u0637\u0644\u0627\u0628 \u0627\u0644\u062f\u0648\u0644\u064a\u064a\u0646\u060c \u062d\u064a\u062b \u064a\u062a\u0645 \u062a\u0648\u0641\u064a\u0631 \u0631\u0627\u062a\u0628 \u0634\u0647\u0631\u064a \u0642\u062f\u0631\u0647 10,000 \u062f\u0631\u0647\u0645 \u0628\u0627\u0644\u0625\u0636\u0627\u0641\u0629 \u0625\u0644\u0649 \u0627\u0644\u0645\u0632\u0627\u064a\u0627 \u0627\u0644\u0623\u062e\u0631\u0649 \u0645\u062b\u0644 \u0627\u0644\u0633\u0643\u0646 \u0627\u0644\u0645\u062c\u0627\u0646\u064a \u0648\u0627\u0644\u062a\u0623\u0645\u064a\u0646 \u0627\u0644\u0635\u062d\u064a.\u003c/p\u003e\u003c/li\u003e\u003c/ol\u003e\u003cp\u003e\u062a\u0635\u0641\u062d \u0627\u0644\u0645\u0632\u064a\u062f \u0645\u0646: \u0645\u0646\u062d \u062f\u0631\u0627\u0633\u064a\u0629\u003c/p\u003e\u003cp\u003e\u0625\u0644\u064a\u0643 \u0623\u064a\u0636\u0627\u064b: \u0645\u0646\u062d \u0628\u0643\u0627\u0644\u0648\u0631\u064a\u0648\u0633 \u0645\u0645\u0648\u0644\u0629 \u0628\u0627\u0644\u0643\u0627\u0645\u0644\u003c/p\u003e\u003cp\u003e\u062a\u0639\u0631\u0641 \u0639\u0644\u0649: \u0623\u0634\u0647\u0631 \u0628\u0631\u0627\u0645\u062c \u0627\u0644\u0645\u0646\u062d \u0627\u0644\u062f\u0631\u0627\u0633\u064a\u0629 \u0641\u064a \u0627\u0644\u0625\u0645\u0627\u0631\u0627\u062a \u0627\u0644\u0639\u0631\u0628\u064a\u0629 \u0627\u0644\u0645\u062a\u062d\u062f\u0629\u003c/p\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e"},{"header":"\u0627\u0644\u0645\u0646\u0627\u0641\u0639 \u0648\u0627\u0644\u0641\u0648\u0627\u0626\u062f","body":"\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cbr\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e"},{"header":"\u0645\u0639\u0627\u064a\u064a\u0631 \u0627\u0644\u062a\u0642\u062f\u064a\u0645","body":"\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cdiv\u003e\u003cbr\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e"}]}});